/**
 * @name Path traversal via HTTP request to file system
 * @description User-controlled input flows to file system operations without adequate validation
 * @kind path-problem
 * @problem.severity error
 * @id java/path-traversal-http-to-file
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get()
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Path.resolve()
    exists(MethodCall mc |
      mc.getMethod().hasName("resolve") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.nio.file", "Path") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // FileInputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ClassLoader.getResource / getResourceAsStream
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResource", "getResourceAsStream"]) and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: user input flows to file system operation from $@.", source.getNode(), "user input"

/**
 * @name Path traversal via ResourceController - HTTP input to file resource
 * @description HTTP request path segments flow to file resource operations in ResourceController
 * @kind path-problem
 * @problem.severity error
 * @id java/resource-controller-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ResourceControllerConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassPathResource or FileSystemResource construction
    exists(ClassInstanceExpr cie |
      (cie.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "ClassPathResource") or
       cie.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "FileSystemResource") or
       cie.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "UrlResource")) and
      sink.asExpr() = cie.getAnArgument()
    )
    or
    // getResource calls
    exists(MethodCall mc |
      mc.getMethod().hasName("getResource") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

