/**
 * @name ResourceController path traversal via user-controlled resource path
 * @description User-controlled input flows to resource loading in ResourceController without adequate path validation
 * @kind path-problem
 * @problem.severity error
 * @id java/resource-controller-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ResourceControllerConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassPathResource constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "ClassPathResource") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileSystemResource
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "FileSystemResource") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ResourceLoader.getResource
    exists(MethodCall mc |
      mc.getMethod().hasName("getResource") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // AbstractScmAccessor.getSearchPaths or related
    exists(MethodCall mc |
      mc.getMethod().hasName("getLocations") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

