/**
 * @name NativeEnvironmentRepository - taint flow from HTTP request to file access
 * @description HTTP input flows through NativeEnvironmentRepository to file system access with only startsWith path checks
 * @kind path-problem
 * @problem.severity error
 * @id java/native-env-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module NativeEnvConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Sinks in NativeEnvironmentRepository
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName(
        "org.springframework.cloud.config.server.environment", "NativeEnvironmentRepository"
      ) and
      (
        mc.getMethod().hasName("startsWith") or
        mc.getMethod().hasName("getLocations") or
        mc.getMethod().hasName("getResource")
      ) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // ClassPathResource constructor inside NativeEnvironmentRepository
    exists(ClassInstanceExpr ce |
      ce.getEnclosingCallable().getDeclaringType().hasQualifiedName(
        "org.springframework.cloud.config.server.environment", "NativeEnvironmentRepository"
      ) and
      ce.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "ClassPathResource") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

