/**
 * @name ResourceController path traversal via cleanPath bypass
 * @description The ResourceController uses Spring's cleanPath() for normalization followed
 *              by a startsWith() check which can be bypassed to access arbitrary files.
 *              Also checks for direct user-controlled path in resource resolution.
 * @kind path-problem
 * @problem.severity error
 * @id java/resource-controller-cleanpath-traversal
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-706
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

// Find calls to StringUtils.cleanPath or similar
class CleanPathCall extends MethodCall {
  CleanPathCall() {
    this.getMethod().hasName("cleanPath") and
    this.getMethod().getDeclaringType().hasQualifiedName("org.springframework.util", "StringUtils")
  }
}

// Find ClassPathResource or FileSystemResource construction
class ResourceConstructionSink extends DataFlow::Node {
  ResourceConstructionSink() {
    exists(ClassInstanceExpr ce |
      (
        ce.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "ClassPathResource") or
        ce.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "FileSystemResource") or
        ce.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "UrlResource")
      ) and
      this.asExpr() = ce.getArgument(0)
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("getResource") and
      this.asExpr() = mc.getArgument(0)
    )
  }
}

module ResourceControllerConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    sink instanceof ResourceConstructionSink
  }
}

