/**
 * @name Path traversal via ResourceController with cleanPath bypass
 * @description HTTP user input (path parameters) flows through ResourceController
 *              into resource loading without adequate protection. The cleanPath() method
 *              does not prevent path traversal via '..' sequences combined with URL encoding
 *              or special characters. This is consistent with CVE-2019-3799.
 * @kind path-problem
 * @problem.severity error
 * @id java/resource-controller-path-traversal-cve
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-023
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ResourceControllerConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Sources: path variables or request parameters in ResourceController
    exists(Method m |
      m.getDeclaringType().hasQualifiedName("org.springframework.cloud.config.server.resource", "ResourceController") and
      source.asParameter() = m.getAParameter()
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink 1: new ClassPathResource(path)
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "ClassPathResource") and
      sink.asExpr() = cie.getArgument(0)
    )
    or
    // Sink 2: resourceLoader.getResource(path)
    exists(MethodCall mc |
      mc.getMethod().hasName("getResource") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Sink 3: new File(path)
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = cie.getArgument(0)
    )
  }
}

