/**
 * @name Path traversal from ResourceController HTTP input to filesystem
 * @description Traces user-supplied path parameters from ResourceController HTTP endpoints
 *              to file system operations, demonstrating the CVE-2019-3799 path traversal pattern.
 * @kind path-problem
 * @problem.severity error
 * @id java/resource-controller-direct-traversal
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ResourceControllerPathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // HTTP path parameters from ResourceController methods
    exists(Parameter p, Method m |
      p = source.asParameter() and
      m = p.getCallable() and
      m.getDeclaringType().hasQualifiedName("org.springframework.cloud.config.server.resource", "ResourceController") and
      (
        m.hasName("retrieve") or
        m.hasName("binary") or
        m.hasName("info")
      )
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassPathResource or other resource constructors
    exists(ClassInstanceExpr cie |
      (
        cie.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "ClassPathResource") or
        cie.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "FileSystemResource") or
        cie.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File")
      ) and
      sink.asExpr() = cie.getAnArgument()
    )
    or
    // ResourceLoader.getResource() sink
    exists(MethodCall mc |
      mc.getMethod().hasName("getResource") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

